// Pull services + suburbs from website sitemap
app.get('/api/projects/:projectId/rank-tracking/website-keywords', async (req, res) => {
  const { projectId } = req.params;
  try {
    const projRes = await pool.query('SELECT * FROM projects WHERE id=$1', [projectId]);
    if (projRes.rows.length === 0) return res.status(404).json({ error: 'Project not found' });
    const p = projRes.rows[0];
    const domain = (p.domain || '').replace(/^https?:\/\//, '').replace(/\/+$/, '');
    if (!domain) return res.status(400).json({ error: 'No domain set in project settings' });

    // Try Yoast sitemap first, then standard
    let sitemapXml = '';
    for (const path of ['/page-sitemap.xml', '/wp-sitemap-posts-page-1.xml', '/sitemap.xml']) {
      try {
        const r = await fetch(`https://${domain}${path}`, { signal: AbortSignal.timeout(10000) });
        if (r.ok) { sitemapXml = await r.text(); if (sitemapXml.includes('<loc>')) break; }
      } catch {}
    }
    if (!sitemapXml) return res.status(400).json({ error: 'Could not fetch sitemap from ' + domain });

    const urls = [...sitemapXml.matchAll(/<loc>(.*?)<\/loc>/g)].map(m => m[1]);
    const skip = new Set(['','contact-us','about-us','about-the-team','blog','privacy-policy','terms-conditions','faq','faqs','reviews','sitemap','service-areas','services','photo-gallery','refund-exchange','thank-you','cart','checkout','my-account','shop','sample-page','testimonials','gallery','portfolio','careers','team','our-team','contact']);

    // Extract suburb pages — standard patterns + custom patterns (e.g. /plumber-{suburb}/)
    const suburbs = urls
      .filter(u => u.includes('/service-areas/') || u.includes('/suburbs/') || u.includes('/locations/'))
      .map(u => {
        const slug = u.replace(/https?:\/\/[^/]+\/(service-areas|suburbs|locations)\//, '').replace(/\/$/, '')
          .replace(/^car-key-replacement-/, '').replace(/-/g, ' ');
        return slug;
      })
      .filter(s => s && s.length > 1);

    // Also detect suburb pages from project's GBP service areas matching any URL
    try {
      const projR2 = await pool.query('SELECT service_areas FROM projects WHERE id=$1', [projectId]);
      const sa2 = projR2.rows[0]?.service_areas;
      if (sa2) {
        const saList = typeof sa2 === 'string' ? JSON.parse(sa2) : sa2;
        if (Array.isArray(saList)) {
          const seen2 = new Set(suburbs.map(s => s.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim()));
          for (const sub of saList) {
            const rawName = (typeof sub === 'string' ? sub : sub.name || '').trim();
            // Strip state/country: "Kedron QLD, Australia" → "Kedron", "Kedron QLD 4000, Australia" → "Kedron"
            const subName = rawName.replace(/\s*(QLD|NSW|VIC|SA|WA|TAS|NT|ACT)\s*\d*\s*,?\s*Australia\s*/gi, '').replace(/\s*,\s*$/, '').trim() || rawName;
            const n = subName.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();
            if (n.length < 3 || seen2.has(n)) continue;
            const slug = n.replace(/\s+/g, '-');
            if (urls.some(u => u.toLowerCase().includes(slug))) {
              seen2.add(n);
              suburbs.push(subName);
            }
          }
        }
      }
    } catch {}

    // Auto-detect suburb pages by prefix pattern: if 8+ URLs share the same prefix, suffix is a suburb
    // Handles both single-word (plumber-{suburb}) and multi-word (blocked-drain-{suburb}) prefixes
    const topLevelSlugs = urls.map(u => u.replace(/https?:\/\/[^/]+\//, '').replace(/\/$/, '').split('/')[0]).filter(Boolean);
    const prefixCounts = {};
    for (const slug of topLevelSlugs) {
      // Try all possible prefix splits: "blocked-drain-kedron" → "blocked-", "blocked-drain-"
      const parts = slug.split('-');
      for (let i = 1; i < parts.length; i++) {
        const prefix = parts.slice(0, i).join('-') + '-';
        prefixCounts[prefix] = (prefixCounts[prefix] || 0) + 1;
      }
    }
    const suburbPrefixes = Object.entries(prefixCounts).filter(([, count]) => count >= 8).map(([prefix]) => prefix)
      // Remove shorter prefixes if a longer one also qualifies (prefer "blocked-drain-" over "blocked-")
      .filter((prefix, _, arr) => !arr.some(other => other !== prefix && other.startsWith(prefix) && prefixCounts[other] >= 8));
    if (suburbPrefixes.length > 0) {
      const seen3 = new Set(suburbs.map(s => s.toLowerCase().trim()));
      for (const slug of topLevelSlugs) {
        for (const prefix of suburbPrefixes) {
          if (slug.startsWith(prefix) && slug.length > prefix.length) {
            const suburbSlug = slug.slice(prefix.length);
            const suburbName = suburbSlug.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
            if (!seen3.has(suburbName.toLowerCase()) && suburbName.length > 2) {
              seen3.add(suburbName.toLowerCase());
              suburbs.push(suburbName);
            }
          }
        }
      }
    }

    // Extract service pages — anything that's not a suburb, not a brand index, not generic
    const brandIndexes = new Set(['a-f','g-j','k-o','p-z']);
    const suburbSlugs = new Set(suburbs.map(s => s.toLowerCase().replace(/\s+/g, '-')));
    const servicePages = [];
    const brandPages = [];
    for (const u of urls) {
      const path = u.replace(/https?:\/\/[^/]+\//, '').replace(/\/$/, '');
      if (!path || skip.has(path) || u.includes('/service-areas/') || u.includes('/suburbs/') || u.includes('/locations/')) continue;
      if (path.startsWith('category/') || path.startsWith('tag/') || path.startsWith('blog/')) continue;
      if (path.match(/^elementor-|^dsfs$|^vbn|^sample/)) continue;
      // Skip suburb pages (e.g. plumber-kedron, blocked-drain-albany-creek)
      const pathLower = path.toLowerCase();
      if (suburbSlugs.has(pathLower) || [...suburbSlugs].some(ss => pathLower.endsWith('-' + ss) || pathLower.includes('/' + ss))) continue;

      const parts = path.split('/');
      if (parts.length === 2 && brandIndexes.has(parts[0])) {
        // Brand page like a-f/toyota-car-key-replacement
        const brand = parts[1].replace(/-car-key-replacement$/, '').replace(/-/g, ' ');
        brandPages.push({ slug: path, name: brand + ' car key replacement', brand: brand });
      } else if (parts.length === 1 && brandIndexes.has(parts[0])) {
        continue; // brand index page
      } else {
        // Service page — clean slug to human-readable name
        let name = path.replace(/services?\//g, '').replace(/-/g, ' ')
          .replace(/\b(in|services?)\b/gi, ' ').replace(/\s{2,}/g, ' ').trim();
        // Strip location suffixes using project location (brisbane, north brisbane, south perth, etc.)
        const cityWord = (p.location || '').toLowerCase().split(/[\s,]+/).find(w => ['brisbane','perth','melbourne','sydney','adelaide','hobart','darwin','canberra','gold coast'].includes(w)) || '';
        if (cityWord) name = name.replace(new RegExp('\\b(north|south|east|west|inner|outer|greater)?\\s*' + cityWord + '\\b', 'gi'), '').trim();
        // Also strip all suburb names from the service name (catches "plumber kedron" → "plumber")
        for (const sub of suburbs) {
          const subLower = sub.toLowerCase().trim();
          if (subLower.length > 2) name = name.replace(new RegExp('\\b' + subLower.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'gi'), '').trim();
        }
        // Remove trailing numbers (duplicate pages like "2", "3") and title case
        name = name.replace(/\s+\d+$/, '').replace(/\s{2,}/g, ' ').trim();
        name = name.replace(/\b\w/g, c => c.toUpperCase());
        if (name.length > 2) servicePages.push({ slug: path, name });
      }
    }

    // Deduplicate services (after location stripping, "toilet repair brisbane" and "toilet repair north brisbane" both become "toilet repair")
    const seenServiceNames = new Set();
    const dedupedServices = [];
    for (const svc of servicePages) {
      const key = svc.name.toLowerCase().trim();
      if (!seenServiceNames.has(key)) {
        seenServiceNames.add(key);
        dedupedServices.push(svc);
      }
    }

    console.log(`[website-keywords] ${domain}: ${dedupedServices.length} services (${servicePages.length} before dedup), ${brandPages.length} brands, ${suburbs.length} suburbs`);
    res.json({ services: dedupedServices, brands: brandPages, suburbs });
  } catch (e) {
    console.error('[website-keywords] Error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// AI generate smart keyword combos
app.post('/api/projects/:projectId/rank-tracking/generate-combos', async (req, res) => {
  const { projectId } = req.params;
  const { services, suburbs, count, mode } = req.body; // mode: '1:1' or 'many'
  try {
    const projRes = await pool.query('SELECT * FROM projects WHERE id=$1', [projectId]);
    if (projRes.rows.length === 0) return res.status(404).json({ error: 'Project not found' });
    const p = projRes.rows[0];
    const msg = await anthropic.messages.create({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 2048,
      messages: [{ role: 'user', content: `You are a local SEO expert generating Google Maps keyword combinations.

Business: ${p.business_name || p.name}
Industry: ${p.industry || 'general'}
Location: ${p.location || 'Australia'}

Services: ${services.join(', ')}
Suburbs: ${suburbs.join(', ')}
Target count: ${count} keywords
Mode: ${mode === '1:1' ? 'One service per suburb (spread evenly)' : 'Multiple services per suburb (full coverage)'}

Generate exactly ${count} keyword combinations pairing services with suburbs. Each combo is a service keyword that will be searched in a specific suburb on Google Maps.

Strategy:
- Prioritize high-intent, high-volume service keywords with closest/most relevant suburbs
- For "1:1" mode: spread services across different suburbs for maximum coverage
- For "many" mode: pair top services with multiple suburbs, prioritize closest suburbs
- Put the most impactful combos first (highest expected search volume)
- Each combo should be a realistic search someone would do on Google Maps

Return ONLY a JSON array of objects with "service" and "suburb" keys. No explanation.
Example: [{"service": "auto locksmith", "suburb": "Vincent"}, ...]` }]
    });
    const text = msg.content[0].text.trim();
    const match = text.match(/\[[\s\S]*\]/);
    let combos = match ? JSON.parse(match[0]) : [];

    // Estimate volumes via DataForSEO if available
    if (DATAFORSEO_AUTH && combos.length > 0) {
      try {
        const keywords = combos.map(c => `${c.service} ${c.suburb}`);
        const controller = new AbortController();
        const timeout = setTimeout(() => controller.abort(), 20000);
        const dfsRes = await fetch('https://api.dataforseo.com/v3/keywords_data/google_ads/search_volume/live', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': DATAFORSEO_AUTH },
          body: JSON.stringify([{ keywords, location_name: 'Australia', language_name: 'English' }]),
          signal: controller.signal,
        });
        clearTimeout(timeout);
        if (dfsRes.ok) {
          const dfsData = await dfsRes.json();
          const volResults = dfsData?.tasks?.[0]?.result || [];
          const volMap = {};
          for (const r of volResults) {
            if (r.keyword && r.search_volume != null) volMap[r.keyword.toLowerCase()] = r.search_volume;
          }
          combos = combos.map(c => ({
            ...c,
            volume: volMap[`${c.service} ${c.suburb}`.toLowerCase()] ?? null
          }));
        }
      } catch (volErr) { console.log(`[generate-combos] Volume error: ${volErr.message}`); }
    }

    res.json({ combos });
  } catch (e) {
    console.error('[generate-combos] Error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

// Add keywords to track
app.post('/api/projects/:projectId/rank-tracking/keywords', async (req, res) => {
  const { projectId } = req.params;
  const { keywords, location_code, location } = req.body; // keywords: string[], location: string (suburb/city for Maps), location_code: number
  if (!Array.isArray(keywords) || keywords.length === 0) return res.status(400).json({ error: 'No keywords provided' });
  try {
    // Enforce grid_scan_limit (only for Maps keywords with location, SERP keywords are unlimited)
    const isMapKeyword = location && location.trim().length > 0;
    if (isMapKeyword) {
      const projR = await pool.query('SELECT grid_scan_limit FROM projects WHERE id=$1', [projectId]);
      const limit = projR.rows[0]?.grid_scan_limit || 50;
      const currentCount = await pool.query("SELECT COUNT(*) FROM rank_keywords WHERE project_id=$1 AND location != ''", [projectId]);
      const current = parseInt(currentCount.rows[0].count);
      const available = limit - current;
      if (available <= 0) return res.status(400).json({ error: `Maps keyword limit reached (${limit}). Upgrade your plan or remove existing keywords.`, limit, current });
    }

    let added = 0;
    for (const kw of keywords) {
      if (!kw || typeof kw !== 'string') continue;
      await pool.query(
        `INSERT INTO rank_keywords (project_id, keyword, location, location_code) VALUES ($1, $2, $3, $4) ON CONFLICT (project_id, keyword, location) DO NOTHING`,
        [projectId, kw.trim(), location || '', location_code || 2036]
      );
      added++;
    }
    const { rows } = await pool.query('SELECT * FROM rank_keywords WHERE project_id=$1 ORDER BY added_at DESC', [projectId]);
    res.json({ ok: true, added, total: rows.length, keywords: rows });
  } catch (e) { res.status(500).json({ error: e.message }); }
});

